insert into event (id, booth_id, title, description, start_time, end_time, reward_info, capacity, tag, subtitle, speaker, standing) values
  ('evs_1', 'b_b104', '볼로냐 국제아동도서전 라가치상 수상 이경국 작가 사인회', '2026 볼로냐 국제 아동도서전 라가치상 CrossMedia 스페셜 멘션 수상, 이경국 작가 신간 『기분의 모양』 작가 사인회를 진행합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '저자 사인회', null, null, true),
  ('evs_2', 'b_a707', '책읽는고양이 도서 구입시 굿즈 증정', '도서를 구입하는 독자께 특별 굿즈를 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_3', 'b_a707', '책읽는고양이 SNS 팔로우 이벤트', '책읽는고양이 부스(A707)로 오세요. SNS 팔로우하시면 굿즈를 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_4', 'b_a802', '소원나무 도서 구매 이벤트', '소원나무 부스에서 도서 구매 시 오직 서울국제도서전에서만 만날 수 있는 키링, 우표 스티커 등의 굿즈를 증정합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_5', 'b_a1102', '윌라, 윌라스토리 부스 체험 이벤트', '독서 플랫폼 윌라 부스에서 전자책·오디오북 체험 후 윌라스토리에서는 생생한 오디오 웹소설을 직접 경험해보세요. 간단한 미션 참여 시, 한정판 위글위글 콜라보 리유저블백을 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_6', 'b_a1002', '나만의 마음공감책 만들기', '감정 질문지와 가치 글귀가 담긴 내지를 직접 선택 및 조합하여 ''나만의 마음공감책''을 만드는 참여형 프로그램. 마음공감책을 통해 일상에서 자기돌봄을 실천할 수 있습니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_7', 'b_a201', '우리가 연결돼 있다는 새파란 증거', '42개 키워드로 하이퍼링크의 힘과 아름다움을 더듬는 책 『하이퍼링크』. 현장에서 위 도서를 구매하는 분들께 우리가 연결돼 있다는 증거를 확인할 수 있는 물체를 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_8', 'b_b304', '『연필』을 읽다, 연필을 만나다: 연필 큐레이션 전시', '책 『연필』 속에서만 보던 역사 속 개성 있는 연필들을 실제로 볼 수 있는 큐레이션 전시입니다. 『작은 연필 가게 흑심』과 함께 준비하였습니다. (빈티지 연필 구입 가능, 한정 수량)', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '기타', null, null, true),
  ('evs_9', 'b_b304', '''서해문집X흑심'' 미니연필세트 증정', '서해문집 적독 서재 부스에서 책을 2권 이상 구매하시는 모든 분께 『작은 연필 가게 흑심』과 함께 제작한 ''미니 연필 세트''(디자인 택1)를 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_10', 'b_a2301', '스탬프 책갈피 투어', '도서관 퀴즈 풀기, 내가 작성한 포스트잇으로 책파도 만들기 등의 체험 후 스탬프를 찍어 나만의 책갈피를 만들고, 특별한 굿즈도 받아가실 수 있습니다!', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_11', 'b_a801', '미래 식량 무료 시식회', '저탄소 식생활을 실천할 수 있는 아이템! 친환경 사육으로 자란 ''식용곤충''을 활용한 미래 식량 시식회를 엽니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_12', 'b_a103', '어린왕자 컬러링 필사북 세트 판매', '어린왕자 그림 컬러링과 필사로 구성된 도서와 굿즈를 판매합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_13', 'b_a103', '볼펜꾸미기 체험', '부카 부스에서 도서를 구매한 독자를 대상으로 한 볼펜꾸미기 체험 행사로, 책을 구매하시면 볼펜꾸미기를 무료로 체험 가능합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_14', 'b_a1905', '장르문학 출판사 스탬프 투어', '장르문학 출판사 부스에서 스탬프를 받고 각 출판사의 장르문학 추구미도 구경해보세요! 저마다의 개성과 매력이 있답니다. 스탬프를 찍을 때마다 주어지는 소소한 특전은 덤입니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_15', 'b_a1701', '[방문 후기] 당신의 기록으로 완성되는 티키타카', '부스에서의 즐거운 순간을 SNS(인스타그램, 블로그 등)에 남겨주세요. 추첨을 통해 도서전의 여운을 간직하게 할 <선물>을 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_16', 'b_a1701', '[문장 기록 이벤트] 그 시절 우리가 읽은 문장', '당신이 태어난 해, 세상은 어떤 문장에 설레었을까요? 역대 베스트셀러 책갈피 속 문장을 교보생명 서재에 등록하면 <스페셜 스티커팩>을 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_17', 'b_a1701', '[웰컴 이벤트] 문장은 쏙- 지갑은 꽉!', '교보생명 앱에서 ''서재'' 회원 인증만 해도 문장을 마음속에 저장할 <문장수집 책갈피>와 부담을 덜어줄 <5,000원 할인 쿠폰>을 드립니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_18', 'b_b103', '종이 왕관 만들기', '좋아하는 그림책 캐릭터 도안을 골라 다양한 채색 도구로 종이 왕관을 꾸며 보세요. 왕처럼 환대받을 자격이 있는 어린이들을 위한 재미있는 공작 프로그램입니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_19', 'b_a1309', '내가 바로 부처! 직접 완성하는 불교 경전 글귀', '문장 카드와 스탬프로 직접 불경 속 글귀를 완성해보는 체험 이벤트가 진행됩니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_20', 'b_a1406', '아프리카 퀼트 책갈피 증정', '『아프리카에서 부르는 바람의 노래』 구매 시 아프리카 현지에서 제작한 퀼트 책갈피를 증정합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_21', 'b_a1406', '아트 카드 증정', '템북 도서 구매 시 『리디밍 러브』와 『씨 뿌리는 자』의 표지 디자인을 활용한 아트 카드를 증정합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evs_22', 'b_a1701', '수신지 작가 사인회', '『며느라기』의 작가 수신지의 신작 『반장으로서의 책임과 의무 7』을 서울국제도서전에서 처음 선보입니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '저자 사인회', null, null, true),
  ('evs_23', 'b_a1701', '사랑하는 당신에게: 도서 구매 시 편지지 증정', '이 책이 남긴 여운을 소중한 사람에게 전해 보세요. 도서 구매 시, 마음을 담을 수 있는 편지지를 증정합니다.', '2026-06-24T01:00:00.000Z', '2026-06-28T09:00:00.000Z', null, null, '이벤트', null, null, true),
  ('evp_2026-06-24_1', 'b_b704', '2026 서울국제도서전 개막식', '', '2026-06-24T01:30:00.000Z', '2026-06-24T03:00:00.000Z', null, null, '개막식', null, null, false),
  ('evp_2026-06-24_2', 'b_a601', '2026 서울국제도서전 주빈 개막식', '', '2026-06-24T02:30:00.000Z', '2026-06-24T03:30:00.000Z', null, null, '개막식', null, null, false),
  ('evp_2026-06-24_3', 'b_a1901', '내가 기다리던 책의 순간 – 인벤토리 책갈피 만들기', '', '2026-06-24T03:30:00.000Z', '2026-06-24T04:30:00.000Z', null, null, '워크숍 프로그램', null, '연사 | 나소연(일러스트레이터)', false),
  ('evp_2026-06-24_4', 'b_a2402', 'AI 시대의 윤리와 저작권 : 출판 산업의 과제', '', '2026-06-24T03:30:00.000Z', '2026-06-24T05:00:00.000Z', null, null, '국제 세미나', null, '연사 | 니콜라 로슈(프랑스 출판네트워크 대표), 도리스 첸(링킹 출판사 GM), 이영욱(변호사, 만화가) / 사회 | 김학희(한국문학예술저작권협회)', false),
  ('evp_2026-06-24_5', 'b_b704', '글쓴이와 옮긴이', '', '2026-06-24T05:00:00.000Z', '2026-06-24T06:30:00.000Z', null, null, '주제 강연', null, '연사 | 백수린(소설가, 번역가), 이주혜(소설가, 번역가), 정보라(데모꾼) / 사회 | 허희(문학평론가)', false),
  ('evp_2026-06-24_6', 'b_a1901', '『건축의 K』 저자와 함께하는 K-미학 건축 탐구', '', '2026-06-24T05:00:00.000Z', '2026-06-24T06:00:00.000Z', null, null, '작가와의 만남', null, '연사 | 노은주(건축가), 임형남(건축가)', false),
  ('evp_2026-06-24_7', 'b_a2402', '세상의 모든 요리, 미식 문화는 어떻게 우리 삶 속에 이야기를 만들어가는가', '', '2026-06-24T05:30:00.000Z', '2026-06-24T07:00:00.000Z', null, null, '해외 작가 강연', null, '연사 | 강현정(번역가), 윤화영(요리사), 프랑수아 레지스 고드리(미식 저널리스트, 작가) / 사회 | 김문영(이숲출판사 대표)', false),
  ('evp_2026-06-24_8', 'b_a1901', '어떤 종의 기원담, 그리고 우리의 미래담: 김보영 작가와의 만남', '', '2026-06-24T06:30:00.000Z', '2026-06-24T07:30:00.000Z', null, null, '작가와의 만남', null, '연사 | 김보영(소설가)', false),
  ('evp_2026-06-24_9', 'b_a601', '[미식체험] 라 벨일 루아즈와 함께하는 프랑스 브르타뉴 미식체험', '', '2026-06-24T07:00:00.000Z', '2026-06-24T07:30:00.000Z', null, null, '주빈 워크숍 프로그램', null, null, false),
  ('evp_2026-06-24_10', 'b_a2402', '바캉스 ''이래도 되나'' 북콘서트', '', '2026-06-24T07:30:00.000Z', '2026-06-24T09:00:00.000Z', null, null, '작가와의 만남', null, '연사 | 강혜숙(그림책 작가), 김유(그림책 작가), 노인경(그림책 작가), 메(그림책 작가), 서현(그림책 작가), 소윤경(그림책 작가), 오세나(그림책 작가), 우영(그림책 작가), 이수지(그림책 작가), 조오(그림책 작가), 조은영(그림책 작가), 현민경(그림책 작가) / 사회 | 정진호(그림책 작가)', false),
  ('evp_2026-06-24_11', 'b_a601', '미래를 읽다 : 프랑스-한국의 책읽는 사회를 위한 공공정책', '', '2026-06-24T07:30:00.000Z', '2026-06-24T08:30:00.000Z', null, null, '주빈 세미나 및 라운드 테이블', null, '연사 | 김진우(한국출판문화산업진흥원 책문화돋움본부장), 손정순(대한출판문화협회 부회장), 솔렌 마렉(프랑스 외무부) / 사회 | 니콜라 로슈(프랑스출판네트워크 대표)', false),
  ('evp_2026-06-24_12', 'b_b704', '2026 한국에서 가장 좋은 책 시상식', '', '2026-06-24T08:00:00.000Z', '2026-06-24T10:00:00.000Z', null, null, '시상식', null, null, false),
  ('evp_2026-06-24_13', 'b_a1901', '이다 작가와 함께하는 일상이 여행이 되는 기록법', '', '2026-06-24T08:00:00.000Z', '2026-06-24T09:00:00.000Z', null, null, '워크숍 프로그램', null, '연사 | 이다(일러스트레이터)', false),
  ('evp_2026-06-25_1', 'b_a2402', '익숙한 세계를 뒤집는 ''재미''', '', '2026-06-25T02:00:00.000Z', '2026-06-25T03:30:00.000Z', null, null, 'BBK 토크', null, '연사 | 김슬기(소설가), 들개이빨(만화가), 오정미(영화 각본가) / 사회 | 전혜정(청강문화산업대학교 만화콘텐츠스쿨 웹소설창작전공 교수)', false),
